customCSS:
/* Winter Frost - Icy Aurora Background */
@import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@300;400;500;600;700&family=Open+Sans:wght@300;400;600&family=Roboto+Mono&display=swap');

/* Static icy gradient background */
.cyber-glow {
  background: 
    radial-gradient(ellipse at 25% 10%, rgba(165, 243, 252, 0.2) 0%, transparent 40%),
    radial-gradient(ellipse at 75% 25%, rgba(147, 197, 253, 0.15) 0%, transparent 35%),
    radial-gradient(ellipse at 50% 60%, rgba(196, 181, 253, 0.1) 0%, transparent 45%),
    linear-gradient(180deg, rgba(240, 249, 255, 0.1) 0%, rgba(165, 243, 252, 0.08) 50%, rgba(147, 197, 253, 0.06) 100%);
  animation: none;
}

.cyber-particles { display: none; }

.stat-card {
  border-radius: 12px;
  border: 1px solid rgba(165, 243, 252, 0.25);
  backdrop-filter: blur(8px);
}

.stat-card::before {
  background: linear-gradient(135deg, #f0f9ff, #a5f3fc, #93c5fd, #c4b5fd);
}

.stat-card:hover {
  box-shadow: 0 0 25px rgba(165, 243, 252, 0.25);
}

.celebration-title {
  background: linear-gradient(135deg, #f0f9ff, #a5f3fc, #93c5fd, #c4b5fd);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  border-radius: 12px;
  backdrop-filter: blur(5px);
}
